function pad(n){ return (n < 10 ? "0" : "") + n; }
function today(){ try { var d = new Date(); return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-" + pad(d.getDate()); } catch (e) { return "YYYY-MM-DD"; } }
function nowStr(){ try { var d = new Date(); return today() + " " + pad(d.getHours()) + ":" + pad(d.getMinutes()); } catch (e) { return "YYYY-MM-DD HH:MM"; } }
